(function () {
  function addStyle() { if (document.getElementById('bac-style')) return; var s = document.createElement('style'); s.id = 'bac-style'; s.textContent = '.bac-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.bac-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:10px}.bac-grid label{display:flex;flex-direction:column;gap:5px}.bac-table{width:100%;border-collapse:collapse;margin-top:10px}.bac-table th,.bac-table td{border:1px solid #e5e7eb;padding:6px;text-align:center}.bac-bad{background:#f8d7da}.bac-ok{padding:10px;border-radius:8px;background:#d4edda;border-left:4px solid #28a745}.bac-no{padding:10px;border-radius:8px;background:#f8d7da;border-left:4px solid #dc3545}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.bacMounted) return; host.dataset.bacMounted = '1'; addStyle(); host.innerHTML = '<div class="bac-wrap"><h4>✅ Kiểm tra tương đương Boole</h4><div class="bac-grid"><label>Biểu thức 1<input data-e1 value="x+y"></label><label>Biểu thức 2<input data-e2 value="y+x"></label></div><p>Dùng + cho OR, · hoặc khoảng trắng cho AND, dấu \' cho NOT. Ví dụ: x·y + x\'.</p><button type="button" data-check>Kiểm tra tương đương</button><div data-out></div></div>'; var out = host.querySelector('[data-out]'); function evalExpr(expr, env) { var i = 0; expr = expr.replace(/\s+/g, ''); function primary() { var v, ch = expr[i]; if (ch === '(') { i++; v = or(); i++; } else if (/[xyz01]/.test(ch)) { i++; v = ch === '1' ? 1 : ch === '0' ? 0 : env[ch]; } else { i++; v = 0; } while (expr[i] === "'") { v = v ? 0 : 1; i++; } return v; } function and() { var v = primary(); while (i < expr.length && expr[i] !== '+' && expr[i] !== ')') { if (expr[i] === '·' || expr[i] === '*') i++; v = v && primary() ? 1 : 0; } return v; } function or() { var v = and(); while (expr[i] === '+') { i++; v = v || and() ? 1 : 0; } return v; } return or() ? 1 : 0; } function check() { var e1 = host.querySelector('[data-e1]').value, e2 = host.querySelector('[data-e2]').value, rows = [], bad = null; for (var x = 0; x < 2; x++) for (var y = 0; y < 2; y++) for (var z = 0; z < 2; z++) { var env = {x:x,y:y,z:z}, a = evalExpr(e1, env), b = evalExpr(e2, env), r = {x:x,y:y,z:z,a:a,b:b}; rows.push(r); if (a !== b && !bad) bad = r; } out.innerHTML = '<div class="' + (bad ? 'bac-no' : 'bac-ok') + '">' + (bad ? 'Không tương đương. Phản ví dụ: x=' + bad.x + ', y=' + bad.y + ', z=' + bad.z + '.' : '✓ Hai biểu thức tương đương trên mọi dòng.') + '</div><table class="bac-table"><tr><th>x</th><th>y</th><th>z</th><th>BT1</th><th>BT2</th></tr>' + rows.map(function (r) { return '<tr class="' + (r.a !== r.b ? 'bac-bad' : '') + '"><td>' + r.x + '</td><td>' + r.y + '</td><td>' + r.z + '</td><td>' + r.a + '</td><td>' + r.b + '</td></tr>'; }).join('') + '</table>'; } host.querySelector('[data-check]').onclick = check; check(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="boolean-algebra-checker"]').forEach(mount); });
}());
